using Microsoft.EntityFrameworkCore;
using Microsoft.EntityFrameworkCore.ChangeTracking;
using Microsoft.EntityFrameworkCore.ValueGeneration;

class BlogContext : DbContext
{
    public DbSet<Blog> Blogs => Set<Blog>();
    protected override void OnModelCreating(ModelBuilder modelBuilder)
    {
        modelBuilder.Entity<Blog>(entity =>
        {
            // Breaking change 1: Discriminator property renamed from "Discriminator" to "$type".
            // Keep old name so existing documents and raw SQL
            // (e.g. SELECT * FROM c WHERE c.Discriminator = 'Blog') still work.
            entity.HasDiscriminator<string>("Discriminator");

            // Breaking change 2: HasIndex() now throws for the Cosmos provider.
            // REMOVED: entity.HasIndex(b => b.Name);

            // Breaking change 3: Cosmos "id" no longer includes discriminator prefix.
            // Old format "Blog|1" → new default "1".
            // Restore old format so existing documents remain accessible.
            entity.Property("__id")
                  .HasValueGenerator<LegacyCosmosIdGenerator>();
        });
    }
}

class Blog { public string Id { get; set; } public string Name { get; set; } }

/// <summary>
/// Generates Cosmos resource ids in the EF Core 8 format: "{Discriminator}|{Key}".
/// </summary>
class LegacyCosmosIdGenerator : ValueGenerator<string>
{
    public override bool GeneratesTemporaryValues => false;

    public override string Next(EntityEntry entry)
    {
        var discriminator = entry.Metadata.GetDiscriminatorValue()?.ToString();
        var key = entry.Property("Id").CurrentValue?.ToString();
        return $"{discriminator}|{key}";
    }
}

